mapper.select:
select st.id as table_id, st.source_file_id as table_source_file_id, st.source_id as table_source_id, st.source_path as table_source_path, st.table_name as table_table_name, st.sheet_name as table_sheet_name, st.format as table_format, st.header_row_number as table_header_row_number, st.row_count as table_row_count, st.column_count as table_column_count, st.metadata_json::text as table_metadata_json, str.id as row_id, str.table_id as row_table_id, str.row_number as row_row_number, str.row_text as row_row_text, str.metadata_json::text as row_metadata_json from structured_table_rows str join structured_tables st on st.id = str.table_id where 1 = 1
and exists ( select 1 from structured_table_cells filter_cell where filter_cell.row_id = str.id and filter_cell.column_name_norm = #{filter.columnNameNorm} and filter_cell.normalized_value = #{filter.normalizedValue} )
order by st.source_path asc, st.table_name asc, str.row_number asc limit #{limit}

select count(*)
from structured_table_rows str
where 1 = 1

    and exists (
        select 1
        from structured_table_cells filter_cell
        where filter_cell.row_id = str.id
          and filter_cell.column_name_norm = #{filter.columnNameNorm}
          and filter_cell.normalized_value = #{filter.normalizedValue}
    )

select group_cell.column_name, group_cell.cell_value, group_cell.normalized_value, min(st.source_id) as source_id, min(st.id) as table_id, min(st.source_path) as source_path, min(st.table_name) as table_name, min(st.sheet_name) as sheet_name, count(*) as row_count from structured_table_rows str join structured_tables st on st.id = str.table_id join structured_table_cells group_cell on group_cell.row_id = str.id where group_cell.column_name_norm = #{groupByFieldNorm}
and exists ( select 1 from structured_table_cells filter_cell where filter_cell.row_id = str.id and filter_cell.column_name_norm = #{filter.columnNameNorm} and filter_cell.normalized_value = #{filter.normalizedValue} )
group by group_cell.column_name, group_cell.cell_value, group_cell.normalized_value order by row_count desc, group_cell.cell_value asc limit #{limit}

select from structured_table_cells where row_id in
#{rowId}
order by row_number asc, column_index asc
